((SELECT id FROM mst_surah WHERE surah_number = 15), 33, 'قَالَ لَمْ أَكُن لِّأَسْجُدَ لِبَشَرٍ خَلَقْتَهُۥ مِن صَلْصَٰلٍۢ مِّنْ حَمَإٍۢ مَّسْنُونٍۢ', NULL, 14, 105, 3, 264, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 34, 'قَالَ فَٱخْرُجْ مِنْهَا فَإِنَّكَ رَجِيمٌۭ', NULL, 14, 105, 3, 264, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 35, 'وَإِنَّ عَلَيْكَ ٱللَّعْنَةَ إِلَىٰ يَوْمِ ٱلدِّينِ', NULL, 14, 105, 3, 264, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 36, 'قَالَ رَبِّ فَأَنظِرْنِىٓ إِلَىٰ يَوْمِ يُبْعَثُونَ', NULL, 14, 105, 3, 264, false, NOW(), NOW()),
