((SELECT id FROM mst_surah WHERE surah_number = 15), 39, 'قَالَ رَبِّ بِمَآ أَغْوَيْتَنِى لَأُزَيِّنَنَّ لَهُمْ فِى ٱلْأَرْضِ وَلَأُغْوِيَنَّهُمْ أَجْمَعِينَ', NULL, 14, 105, 3, 264, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 40, 'إِلَّا عِبَادَكَ مِنْهُمُ ٱلْمُخْلَصِينَ', NULL, 14, 105, 3, 264, false, NOW(), NOW()),
