((SELECT id FROM mst_surah WHERE surah_number = 15), 43, 'وَإِنَّ جَهَنَّمَ لَمَوْعِدُهُمْ أَجْمَعِينَ', NULL, 14, 105, 3, 264, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 44, 'لَهَا سَبْعَةُ أَبْوَٰبٍۢ لِّكُلِّ بَابٍۢ مِّنْهُمْ جُزْءٌۭ مَّقْسُومٌ', NULL, 14, 105, 3, 264, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 45, 'إِنَّ ٱلْمُتَّقِينَ فِى جَنَّٰتٍۢ وَعُيُونٍ', NULL, 14, 105, 3, 264, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 46, 'ٱدْخُلُوهَا بِسَلَٰمٍ ءَامِنِينَ', NULL, 14, 105, 3, 264, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 47, 'وَنَزَعْنَا مَا فِى صُدُورِهِم مِّنْ غِلٍّ إِخْوَٰنًا عَلَىٰ سُرُرٍۢ مُّتَقَٰبِلِينَ', NULL, 14, 105, 3, 264, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 48, 'لَا يَمَسُّهُمْ فِيهَا نَصَبٌۭ وَمَا هُم مِّنْهَا بِمُخْرَجِينَ', NULL, 14, 105, 3, 264, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 49, '۞ نَبِّئْ عِبَادِىٓ أَنِّىٓ أَنَا ٱلْغَفُورُ ٱلرَّحِيمُ', NULL, 14, 105, 3, 264, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 50, 'وَأَنَّ عَذَابِى هُوَ ٱلْعَذَابُ ٱلْأَلِيمُ', NULL, 14, 106, 3, 264, false, NOW(), NOW()),
