((SELECT id FROM mst_surah WHERE surah_number = 15), 52, 'إِذْ دَخَلُوا۟ عَلَيْهِ فَقَالُوا۟ سَلَٰمًۭا قَالَ إِنَّا مِنكُمْ وَجِلُونَ', NULL, 14, 106, 3, 265, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 53, 'قَالُوا۟ لَا تَوْجَلْ إِنَّا نُبَشِّرُكَ بِغُلَٰمٍ عَلِيمٍۢ', NULL, 14, 106, 3, 265, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 54, 'قَالَ أَبَشَّرْتُمُونِى عَلَىٰٓ أَن مَّسَّنِىَ ٱلْكِبَرُ فَبِمَ تُبَشِّرُونَ', NULL, 14, 106, 3, 265, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 55, 'قَالُوا۟ بَشَّرْنَٰكَ بِٱلْحَقِّ فَلَا تَكُن مِّنَ ٱلْقَٰنِطِينَ', NULL, 14, 106, 3, 265, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 56, 'قَالَ وَمَن يَقْنَطُ مِن رَّحْمَةِ رَبِّهِۦٓ إِلَّا ٱلضَّآلُّونَ', NULL, 14, 106, 3, 265, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 57, 'قَالَ فَمَا خَطْبُكُمْ أَيُّهَا ٱلْمُرْسَلُونَ', NULL, 14, 106, 3, 265, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 58, 'قَالُوٓا۟ إِنَّآ أُرْسِلْنَآ إِلَىٰ قَوْمٍۢ مُّجْرِمِينَ', NULL, 14, 106, 3, 265, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 59, 'إِلَّآ ءَالَ لُوطٍ إِنَّا لَمُنَجُّوهُمْ أَجْمَعِينَ', NULL, 14, 106, 3, 265, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 60, 'إِلَّا ٱمْرَأَتَهُۥ قَدَّرْنَآ ۙ إِنَّهَا لَمِنَ ٱلْغَٰبِرِينَ', NULL, 14, 106, 3, 265, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 61, 'فَلَمَّا جَآءَ ءَالَ لُوطٍ ٱلْمُرْسَلُونَ', NULL, 14, 106, 3, 265, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 62, 'قَالَ إِنَّكُمْ قَوْمٌۭ مُّنكَرُونَ', NULL, 14, 106, 3, 265, false, NOW(), NOW()),
