((SELECT id FROM mst_surah WHERE surah_number = 15), 64, 'وَأَتَيْنَٰكَ بِٱلْحَقِّ وَإِنَّا لَصَٰدِقُونَ', NULL, 14, 106, 3, 265, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 65, 'فَأَسْرِ بِأَهْلِكَ بِقِطْعٍۢ مِّنَ ٱلَّيْلِ وَٱتَّبِعْ أَدْبَٰرَهُمْ وَلَا يَلْتَفِتْ مِنكُمْ أَحَدٌۭ وَٱمْضُوا۟ حَيْثُ تُؤْمَرُونَ', NULL, 14, 106, 3, 265, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 66, 'وَقَضَيْنَآ إِلَيْهِ ذَٰلِكَ ٱلْأَمْرَ أَنَّ دَابِرَ هَٰٓؤُلَآءِ مَقْطُوعٌۭ مُّصْبِحِينَ', NULL, 14, 106, 3, 265, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 67, 'وَجَآءَ أَهْلُ ٱلْمَدِينَةِ يَسْتَبْشِرُونَ', NULL, 14, 106, 3, 265, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 68, 'قَالَ إِنَّ هَٰٓؤُلَآءِ ضَيْفِى فَلَا تَفْضَحُونِ', NULL, 14, 106, 3, 265, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 69, 'وَٱتَّقُوا۟ ٱللَّهَ وَلَا تُخْزُونِ', NULL, 14, 106, 3, 265, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 70, 'قَالُوٓا۟ أَوَلَمْ نَنْهَكَ عَنِ ٱلْعَٰلَمِينَ', NULL, 14, 106, 3, 265, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 71, 'قَالَ هَٰٓؤُلَآءِ بَنَاتِىٓ إِن كُنتُمْ فَٰعِلِينَ', NULL, 14, 106, 3, 266, false, NOW(), NOW()),
