((SELECT id FROM mst_surah WHERE surah_number = 15), 74, 'فَجَعَلْنَا عَٰلِيَهَا سَافِلَهَا وَأَمْطَرْنَا عَلَيْهِمْ حِجَارَةًۭ مِّن سِجِّيلٍ', NULL, 14, 106, 3, 266, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 75, 'إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّلْمُتَوَسِّمِينَ', NULL, 14, 106, 3, 266, false, NOW(), NOW()),
