((SELECT id FROM mst_surah WHERE surah_number = 15), 77, 'إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لِّلْمُؤْمِنِينَ', NULL, 14, 106, 3, 266, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 78, 'وَإِن كَانَ أَصْحَٰبُ ٱلْأَيْكَةِ لَظَٰلِمِينَ', NULL, 14, 106, 3, 266, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 79, 'فَٱنتَقَمْنَا مِنْهُمْ وَإِنَّهُمَا لَبِإِمَامٍۢ مُّبِينٍۢ', NULL, 14, 106, 3, 266, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 80, 'وَلَقَدْ كَذَّبَ أَصْحَٰبُ ٱلْحِجْرِ ٱلْمُرْسَلِينَ', NULL, 14, 106, 3, 266, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 81, 'وَءَاتَيْنَٰهُمْ ءَايَٰتِنَا فَكَانُوا۟ عَنْهَا مُعْرِضِينَ', NULL, 14, 106, 3, 266, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 82, 'وَكَانُوا۟ يَنْحِتُونَ مِنَ ٱلْجِبَالِ بُيُوتًا ءَامِنِينَ', NULL, 14, 106, 3, 266, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 83, 'فَأَخَذَتْهُمُ ٱلصَّيْحَةُ مُصْبِحِينَ', NULL, 14, 106, 3, 266, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 84, 'فَمَآ أَغْنَىٰ عَنْهُم مَّا كَانُوا۟ يَكْسِبُونَ', NULL, 14, 106, 3, 266, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 85, 'وَمَا خَلَقْنَا ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ وَمَا بَيْنَهُمَآ إِلَّا بِٱلْحَقِّ ۗ وَإِنَّ ٱلسَّاعَةَ لَءَاتِيَةٌۭ ۖ فَٱصْفَحِ ٱلصَّفْحَ ٱلْجَمِيلَ', NULL, 14, 106, 3, 266, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 86, 'إِنَّ رَبَّكَ هُوَ ٱلْخَلَّٰقُ ٱلْعَلِيمُ', NULL, 14, 106, 3, 266, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 87, 'وَلَقَدْ ءَاتَيْنَٰكَ سَبْعًۭا مِّنَ ٱلْمَثَانِى وَٱلْقُرْءَانَ ٱلْعَظِيمَ', NULL, 14, 106, 3, 266, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 88, 'لَا تَمُدَّنَّ عَيْنَيْكَ إِلَىٰ مَا مَتَّعْنَا بِهِۦٓ أَزْوَٰجًۭا مِّنْهُمْ وَلَا تَحْزَنْ عَلَيْهِمْ وَٱخْفِضْ جَنَاحَكَ لِلْمُؤْمِنِينَ', NULL, 14, 106, 3, 266, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 89, 'وَقُلْ إِنِّىٓ أَنَا ٱلنَّذِيرُ ٱلْمُبِينُ', NULL, 14, 106, 3, 266, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 90, 'كَمَآ أَنزَلْنَا عَلَى ٱلْمُقْتَسِمِينَ', NULL, 14, 106, 3, 266, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 91, 'ٱلَّذِينَ جَعَلُوا۟ ٱلْقُرْءَانَ عِضِينَ', NULL, 14, 106, 3, 267, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 92, 'فَوَرَبِّكَ لَنَسْـَٔلَنَّهُمْ أَجْمَعِينَ', NULL, 14, 106, 3, 267, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 93, 'عَمَّا كَانُوا۟ يَعْمَلُونَ', NULL, 14, 106, 3, 267, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 94, 'فَٱصْدَعْ بِمَا تُؤْمَرُ وَأَعْرِضْ عَنِ ٱلْمُشْرِكِينَ', NULL, 14, 106, 3, 267, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 95, 'إِنَّا كَفَيْنَٰكَ ٱلْمُسْتَهْزِءِينَ', NULL, 14, 106, 3, 267, false, NOW(), NOW()),
