((SELECT id FROM mst_surah WHERE surah_number = 15), 97, 'وَلَقَدْ نَعْلَمُ أَنَّكَ يَضِيقُ صَدْرُكَ بِمَا يَقُولُونَ', NULL, 14, 106, 3, 267, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 98, 'فَسَبِّحْ بِحَمْدِ رَبِّكَ وَكُن مِّنَ ٱلسَّٰجِدِينَ', NULL, 14, 106, 3, 267, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 15), 99, 'وَٱعْبُدْ رَبَّكَ حَتَّىٰ يَأْتِيَكَ ٱلْيَقِينُ', NULL, 14, 106, 3, 267, false, NOW(), NOW()),
